const stdout = $('Docker Health').first().json.stdout;

// Parsing output gabungan
const runningSection = stdout.split('===RUNNING===\n')[1].split('===RESTARTS===')[0].trim();
const restartsSection = stdout.split('===RESTARTS===\n')[1].split('===VOLUMES===')[0].trim();
const volumesVal = stdout.split('===VOLUMES===\n')[1].split('===IMAGES===')[0].trim();
const imagesVal = stdout.split('===IMAGES===\n')[1].split('===DANGLING===')[0].trim();
const danglingVal = parseInt(stdout.split('===DANGLING===\n')[1].trim());

// Logika Deteksi Restart Abnormal
const restartLines = restartsSection.split('\n');
let abnormalRestarts = [];
for (const line of restartLines) {
  const parts = line.split(': ');
  if (parts.length === 2) {
    const name = parts[0].replace('/', '');
    const count = parseInt(parts[1]);
    if (count > 0) {
      abnormalRestarts.push(`${name} (${count}x)`);
    }
  }
}

const isAbnormal = abnormalRestarts.length > 0 
  ? `⚠ Ya (Terjadi Restart di: ${abnormalRestarts.join(', ')})` 
  : "✔ Tidak";

// Logika Cleanup Status
const cleanupStatus = danglingVal > 0 
  ? `⚠ Perlu Cleanup (Ada ${danglingVal} dangling image)` 
  : "✔ Bersih";

// Logika Notes Otomatis
const notes = abnormalRestarts.length > 0 
  ? "Harap periksa logs container yang sering restart." 
  : "Semua kontainer Docker berjalan optimal dan efisien.";

// Output data bersih
return [{
  json: {
    running_containers: runningSection,
    restart_abnormal: isAbnormal,
    volume_size: volumesVal,
    image_size: imagesVal,
    cleanup_status: cleanupStatus,
    notes: notes
  }
}];

const stdout = $('Cronjob').first().json.stdout;

const listVal = stdout.split('===LIST===\n')[1].split('===FAILING===')[0].trim();
const failingVal = stdout.split('===FAILING===\n')[1].split('===CHANGES===')[0].trim();
const changesVal = stdout.split('===CHANGES===\n')[1].trim();

const isFailing = failingVal.toLowerCase().includes('error') || failingVal.toLowerCase().includes('fail')
  ? `⚠ Ya (Terjadi error di syslog)`
  : "✔ Tidak";

const notes = isFailing.includes('Ya')
  ? "Terdeteksi kegagalan eksekusi cronjob di log sistem. Harap periksa syslog."
  : "Tugas terjadwal (cronjob) berjalan lancar tanpa error.";

return [{
  json: {
    cronjob_list: listVal,
    cronjob_failing: isFailing,
    schedule_changes: changesVal,
    notes: notes
  }
}];

const stdout = $('Security Audit').first().json.stdout.trim();

try {
  // Membersihkan tanda markdown ```json jika disertakan oleh AI
  const cleanJsonText = stdout.replace(/```json/g, '').replace(/```/g, '').trim();
  const parsedData = JSON.parse(cleanJsonText);

  return [{ json: parsedData }];
} catch (error) {
  // Fallback jika terjadi error parsing
  return [{
    json: {
      ssh_login: "Gagal memindai log",
      suspicious_ip: "Tidak dapat dideteksi",
      update_packages: "Gagal memeriksa update",
      ssl_expiry: "Gagal mendeteksi SSL",
      firewall_status: "Gagal memeriksa UFW",
      notes: "Error parsing data AI: " + error.message
    }
  }];
}

